PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:42', 77, 42, 29, 581, 5664, 'وَّفَوَاكِهَ مِمَّا يَشْتَهُوْنَۗ', 'serta buah-buahan yang mereka sukai. ', '', 'https://everyayah.com/data/Alafasy_128kbps/077042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:43', 77, 43, 29, 581, 5665, 'كُلُوْا وَاشْرَبُوْا هَنِيْۤـًٔا ۢبِمَا كُنْتُمْ تَعْمَلُوْنَ ', '(Dikatakan kepada mereka,) “Makan dan minumlah dengan nikmat karena apa yang selalu kamu kerjakan.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/077043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:44', 77, 44, 29, 581, 5666, 'اِنَّا كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ ', 'Sesungguhnya demikianlah Kami beri balasan kepada orang-orang yang berbuat baik. ', '', 'https://everyayah.com/data/Alafasy_128kbps/077044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:45', 77, 45, 29, 581, 5667, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:46', 77, 46, 29, 581, 5668, 'كُلُوْا وَتَمَتَّعُوْا قَلِيْلًا اِنَّكُمْ مُّجْرِمُوْنَ ', '(Dikatakan kepada orang-orang kafir,) “Makan dan bersenang-senanglah kamu (di dunia) sebentar. Sesungguhnya kamu adalah para pendurhaka!”', '', 'https://everyayah.com/data/Alafasy_128kbps/077046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:47', 77, 47, 29, 581, 5669, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:48', 77, 48, 29, 581, 5670, 'وَاِذَا قِيْلَ لَهُمُ ارْكَعُوْا لَا يَرْكَعُوْنَ ', 'Apabila dikatakan kepada mereka, “Rukuklah,” mereka tidak mau rukuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/077048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:49', 77, 49, 29, 581, 5671, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَ ', 'Celakalah pada hari itu para pendusta (kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/077049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('77:50', 77, 50, 29, 581, 5672, 'فَبِاَيِّ حَدِيْثٍۢ بَعْدَهٗ يُؤْمِنُوْنَ ࣖ   ۔', 'Maka, pada perkataan manakah sesudahnya (Al-Qur’an) mereka akan beriman?', '', 'https://everyayah.com/data/Alafasy_128kbps/077050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:1', 78, 1, 30, 582, 5673, 'عَمَّ يَتَسَاۤءَلُوْنَۚ ', 'Tentang apakah mereka saling bertanya?', '', 'https://everyayah.com/data/Alafasy_128kbps/078001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:2', 78, 2, 30, 582, 5674, 'عَنِ النَّبَاِ الْعَظِيْمِۙ ', 'Tentang berita yang besar (hari Kebangkitan)', '', 'https://everyayah.com/data/Alafasy_128kbps/078002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:3', 78, 3, 30, 582, 5675, 'الَّذِيْ هُمْ فِيْهِ مُخْتَلِفُوْنَۗ ', 'yang dalam hal itu mereka berselisih.', '', 'https://everyayah.com/data/Alafasy_128kbps/078003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:4', 78, 4, 30, 582, 5676, 'كَلَّا سَيَعْلَمُوْنَۙ ', 'Sekali-kali tidak! Kelak mereka akan mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/078004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:5', 78, 5, 30, 582, 5677, 'ثُمَّ كَلَّا سَيَعْلَمُوْنَ', 'Sekali lagi, tidak! Kelak mereka akan mengetahui. ', '', 'https://everyayah.com/data/Alafasy_128kbps/078005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:6', 78, 6, 30, 582, 5678, 'اَلَمْ نَجْعَلِ الْاَرْضَ مِهٰدًاۙ', 'Bukankah Kami telah menjadikan bumi sebagai hamparan ', '', 'https://everyayah.com/data/Alafasy_128kbps/078006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:7', 78, 7, 30, 582, 5679, 'وَّالْجِبَالَ اَوْتَادًاۖ', 'dan gunung-gunung sebagai pasak?', '', 'https://everyayah.com/data/Alafasy_128kbps/078007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:8', 78, 8, 30, 582, 5680, 'وَّخَلَقْنٰكُمْ اَزْوَاجًاۙ ', 'Kami menciptakan kamu berpasang-pasangan.', '', 'https://everyayah.com/data/Alafasy_128kbps/078008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:9', 78, 9, 30, 582, 5681, 'وَّجَعَلْنَا نَوْمَكُمْ سُبَاتًاۙ ', 'Kami menjadikan tidurmu untuk beristirahat.', '', 'https://everyayah.com/data/Alafasy_128kbps/078009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:10', 78, 10, 30, 582, 5682, 'وَّجَعَلْنَا الَّيْلَ لِبَاسًاۙ ', 'Kami menjadikan malam sebagai pakaian.742)', '742) Malam disebut sebagai pakaian karena kegelapannya menutupi alam sebagaimana pakaian menutupi tubuh manusia.', 'https://everyayah.com/data/Alafasy_128kbps/078010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:11', 78, 11, 30, 582, 5683, 'وَّجَعَلْنَا النَّهَارَ مَعَاشًاۚ', 'Kami menjadikan siang untuk mencari penghidupan.', '', 'https://everyayah.com/data/Alafasy_128kbps/078011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:12', 78, 12, 30, 582, 5684, 'وَبَنَيْنَا فَوْقَكُمْ سَبْعًا شِدَادًاۙ ', 'Kami membangun tujuh (langit) yang kukuh di atasmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/078012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:13', 78, 13, 30, 582, 5685, 'وَّجَعَلْنَا سِرَاجًا وَّهَّاجًاۖ', 'Kami menjadikan pelita yang terang-benderang (matahari).', '', 'https://everyayah.com/data/Alafasy_128kbps/078013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:14', 78, 14, 30, 582, 5686, 'وَّاَنْزَلْنَا مِنَ الْمُعْصِرٰتِ مَاۤءً ثَجَّاجًاۙ', 'Kami menurunkan dari awan air hujan yang tercurah dengan deras ', '', 'https://everyayah.com/data/Alafasy_128kbps/078014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:15', 78, 15, 30, 582, 5687, 'لِّنُخْرِجَ بِهٖ حَبًّا وَّنَبَاتًاۙ', 'agar Kami menumbuhkan dengannya biji-bijian, tanam-tanaman,', '', 'https://everyayah.com/data/Alafasy_128kbps/078015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:16', 78, 16, 30, 582, 5688, 'وَّجَنّٰتٍ اَلْفَافًاۗ', 'dan kebun-kebun yang rindang.', '', 'https://everyayah.com/data/Alafasy_128kbps/078016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:17', 78, 17, 30, 582, 5689, 'اِنَّ يَوْمَ الْفَصْلِ كَانَ مِيْقَاتًاۙ', 'Sesungguhnya hari Keputusan itu adalah waktu yang telah ditetapkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/078017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:18', 78, 18, 30, 582, 5690, 'يَّوْمَ يُنْفَخُ فِى الصُّوْرِ فَتَأْتُوْنَ اَفْوَاجًاۙ', '(yaitu) hari (ketika) sangkakala ditiup, lalu kamu datang berbondong-bondong.', '', 'https://everyayah.com/data/Alafasy_128kbps/078018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:19', 78, 19, 30, 582, 5691, 'وَّفُتِحَتِ السَّمَاۤءُ فَكَانَتْ اَبْوَابًاۙ', 'Langit pun dibuka. Maka, terdapatlah beberapa pintu.', '', 'https://everyayah.com/data/Alafasy_128kbps/078019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:20', 78, 20, 30, 582, 5692, 'وَّسُيِّرَتِ الْجِبَالُ فَكَانَتْ سَرَابًاۗ', 'Gunung-gunung pun dijalankan. Maka, ia menjadi (seperti) fatamorgana.', '', 'https://everyayah.com/data/Alafasy_128kbps/078020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:21', 78, 21, 30, 582, 5693, 'اِنَّ جَهَنَّمَ كَانَتْ مِرْصَادًاۙ', 'Sesungguhnya (neraka) Jahanam itu (merupakan) tempat mengintai (bagi penjaga neraka) ', '', 'https://everyayah.com/data/Alafasy_128kbps/078021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:22', 78, 22, 30, 582, 5694, 'لِّلطّٰغِيْنَ مَاٰبًاۙ', '(dan) menjadi tempat kembali bagi orang-orang yang melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/078022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:23', 78, 23, 30, 582, 5695, 'لّٰبِثِيْنَ فِيْهَآ اَحْقَابًاۚ', 'Mereka tinggal di sana dalam masa yang lama.', '', 'https://everyayah.com/data/Alafasy_128kbps/078023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:24', 78, 24, 30, 582, 5696, 'لَا يَذُوْقُوْنَ فِيْهَا بَرْدًا وَّلَا شَرَابًاۙ', 'Mereka tidak merasakan kesejukan di dalamnya dan tidak (pula mendapat) minuman,', '', 'https://everyayah.com/data/Alafasy_128kbps/078024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:25', 78, 25, 30, 582, 5697, 'اِلَّا حَمِيْمًا وَّغَسَّاقًاۙ', 'selain air yang mendidih dan nanah,', '', 'https://everyayah.com/data/Alafasy_128kbps/078025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:26', 78, 26, 30, 582, 5698, 'جَزَاۤءً وِّفَاقًاۗ', 'sebagai pembalasan yang setimpal.', '', 'https://everyayah.com/data/Alafasy_128kbps/078026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:27', 78, 27, 30, 582, 5699, 'اِنَّهُمْ كَانُوْا لَا يَرْجُوْنَ حِسَابًاۙ', 'Sesungguhnya mereka tidak pernah mengharapkan perhitungan.', '', 'https://everyayah.com/data/Alafasy_128kbps/078027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:28', 78, 28, 30, 582, 5700, 'وَّكَذَّبُوْا بِاٰيٰتِنَا كِذَّابًاۗ', 'Mereka benar-benar mendustakan ayat-ayat Kami.', '', 'https://everyayah.com/data/Alafasy_128kbps/078028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:29', 78, 29, 30, 582, 5701, 'وَكُلَّ شَيْءٍ اَحْصَيْنٰهُ كِتٰبًاۙ', 'Segala sesuatu telah Kami catat dalam kitab (catatan amal manusia). ', '', 'https://everyayah.com/data/Alafasy_128kbps/078029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:30', 78, 30, 30, 582, 5702, 'فَذُوْقُوْا فَلَنْ نَّزِيْدَكُمْ اِلَّا عَذَابًا ࣖ', 'Oleh karena itu, rasakanlah! Tidak akan Kami tambahkan kepadamu, kecuali azab.', '', 'https://everyayah.com/data/Alafasy_128kbps/078030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:31', 78, 31, 30, 583, 5703, 'اِنَّ لِلْمُتَّقِيْنَ مَفَازًاۙ', 'Sesungguhnya bagi orang-orang yang bertakwa (ada) kemenangan (surga),', '', 'https://everyayah.com/data/Alafasy_128kbps/078031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:32', 78, 32, 30, 583, 5704, 'حَدَاۤىِٕقَ وَاَعْنَابًاۙ', '(yaitu) kebun-kebun, buah anggur,', '', 'https://everyayah.com/data/Alafasy_128kbps/078032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:33', 78, 33, 30, 583, 5705, 'وَّكَوَاعِبَ اَتْرَابًاۙ', 'gadis-gadis molek yang sebaya,', '', 'https://everyayah.com/data/Alafasy_128kbps/078033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:34', 78, 34, 30, 583, 5706, 'وَّكَأْسًا دِهَاقًاۗ', 'dan gelas-gelas yang penuh (berisi minuman).', '', 'https://everyayah.com/data/Alafasy_128kbps/078034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:35', 78, 35, 30, 583, 5707, 'لَا يَسْمَعُوْنَ فِيْهَا لَغْوًا وَّلَا كِذّٰبًا', 'Di sana mereka tidak mendengar percakapan yang sia-sia dan tidak pula (perkataan) dusta.', '', 'https://everyayah.com/data/Alafasy_128kbps/078035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:36', 78, 36, 30, 583, 5708, 'جَزَاۤءً مِّنْ رَّبِّكَ عَطَاۤءً حِسَابًاۙ', '(Hal itu) sebagai balasan (dan) pemberian yang banyak dari Tuhanmu,', '', 'https://everyayah.com/data/Alafasy_128kbps/078036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:37', 78, 37, 30, 583, 5709, 'رَّبِّ السَّمٰوٰتِ وَالْاَرْضِ وَمَا بَيْنَهُمَا الرَّحْمٰنِ لَا يَمْلِكُوْنَ مِنْهُ خِطَابًاۚ ', '(yaitu) Tuhan (pemelihara) langit, bumi, dan apa yang ada di antara keduanya, Yang Maha Pengasih. Mereka tidak memiliki (hak) berbicara dengan-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/078037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:38', 78, 38, 30, 583, 5710, 'يَوْمَ يَقُوْمُ الرُّوْحُ وَالْمَلٰۤىِٕكَةُ صَفًّاۙ  لَّا يَتَكَلَّمُوْنَ اِلَّا مَنْ اَذِنَ لَهُ الرَّحْمٰنُ وَقَالَ صَوَابًا', 'Pada hari ketika Rūḥ743) dan malaikat berdiri bersaf-saf. Mereka tidak berbicara, kecuali yang diizinkan oleh Tuhan Yang Maha Pengasih dan dia mengatakan yang benar.', '743) Para ahli tafsir berbeda pendapat mengenai maksud rūḥ pada ayat ini. Ada yang memahaminya sebagai Jibril, tentara Allah, atau malaikat yang diserahi tugas mengurus arwah dan sejenisnya.', 'https://everyayah.com/data/Alafasy_128kbps/078038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:39', 78, 39, 30, 583, 5711, 'ذٰلِكَ الْيَوْمُ الْحَقُّۚ فَمَنْ شَاۤءَ اتَّخَذَ اِلٰى رَبِّهٖ مَاٰبًا', 'Itulah hari yang hak (pasti terjadi). Siapa yang menghendaki (keselamatan) niscaya menempuh jalan kembali kepada Tuhannya (dengan beramal saleh).', '', 'https://everyayah.com/data/Alafasy_128kbps/078039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('78:40', 78, 40, 30, 583, 5712, 'اِنَّآ اَنْذَرْنٰكُمْ عَذَابًا قَرِيْبًا ەۙ يَّوْمَ يَنْظُرُ الْمَرْءُ مَا قَدَّمَتْ يَدَاهُ وَيَقُوْلُ الْكٰفِرُ يٰلَيْتَنِيْ كُنْتُ تُرٰبًا ࣖ', 'Sesungguhnya Kami telah memperingatkan kamu akan azab yang dekat pada hari (ketika) manusia melihat apa yang telah diperbuat oleh kedua tangannya dan orang kafir berkata, “Oh, seandainya saja aku menjadi tanah.”', '', 'https://everyayah.com/data/Alafasy_128kbps/078040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:1', 79, 1, 30, 583, 5713, 'وَالنّٰزِعٰتِ غَرْقًاۙ', 'Demi (malaikat) yang mencabut (nyawa orang kafir) dengan keras,', '', 'https://everyayah.com/data/Alafasy_128kbps/079001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:2', 79, 2, 30, 583, 5714, 'وَّالنّٰشِطٰتِ نَشْطًاۙ', 'demi (malaikat) yang mencabut (nyawa orang mukmin) dengan lemah lembut,', '', 'https://everyayah.com/data/Alafasy_128kbps/079002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:3', 79, 3, 30, 583, 5715, 'وَّالسّٰبِحٰتِ سَبْحًاۙ', 'demi (malaikat) yang cepat (menunaikan tugasnya) dengan mudah,', '', 'https://everyayah.com/data/Alafasy_128kbps/079003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:4', 79, 4, 30, 583, 5716, 'فَالسّٰبِقٰتِ سَبْقًاۙ', '(malaikat) yang bergegas (melaksanakan perintah Allah) dengan cepat,', '', 'https://everyayah.com/data/Alafasy_128kbps/079004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:5', 79, 5, 30, 583, 5717, 'فَالْمُدَبِّرٰتِ اَمْرًاۘ', 'dan (malaikat) yang mengatur urusan (dunia),744)', '744) Dalam ayat 1‒5 Allah bersumpah dengan malaikat yang bermacam-macam sifat dan urusannya bahwa manusia akan dibangkitkan pada hari Kiamat. Sebagian mufasir berpendapat bahwa dalam ayat-ayat ini, kecuali ayat 5, Allah bersumpah dengan bintang-bintang.', 'https://everyayah.com/data/Alafasy_128kbps/079005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:6', 79, 6, 30, 583, 5718, 'يَوْمَ تَرْجُفُ الرَّاجِفَةُۙ', '(kamu benar-benar akan dibangkitkan) pada hari ketika tiupan pertama mengguncang (alam semesta).', '', 'https://everyayah.com/data/Alafasy_128kbps/079006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:7', 79, 7, 30, 583, 5719, 'تَتْبَعُهَا الرَّادِفَةُ ۗ', '(Tiupan pertama) itu diiringi oleh tiupan kedua.', '', 'https://everyayah.com/data/Alafasy_128kbps/079007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:8', 79, 8, 30, 583, 5720, 'قُلُوْبٌ يَّوْمَىِٕذٍ وَّاجِفَةٌۙ', 'Hati manusia pada hari itu merasa sangat takut;', '', 'https://everyayah.com/data/Alafasy_128kbps/079008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:9', 79, 9, 30, 583, 5721, 'اَبْصَارُهَا خَاشِعَةٌ  ۘ', 'pandangannya tertunduk.', '', 'https://everyayah.com/data/Alafasy_128kbps/079009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:10', 79, 10, 30, 583, 5722, 'يَقُوْلُوْنَ ءَاِنَّا لَمَرْدُوْدُوْنَ فِى الْحَافِرَةِۗ', 'Mereka (di dunia) berkata, “Apakah kita benar-benar akan dikembalikan pada kehidupan yang semula?745)', '745) Setelah orang-orang kafir mendengar berita tentang adanya hari Kebangkitan setelah mati, mereka merasa heran dan mengejek karena menurut keyakinan mereka, hari Kebangkitan itu tidak ada. Itulah sebabnya mereka berkata demikian.', 'https://everyayah.com/data/Alafasy_128kbps/079010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:11', 79, 11, 30, 583, 5723, 'ءَاِذَا كُنَّا عِظَامًا نَّخِرَةً ۗ', 'Apabila kita telah menjadi tulang-belulang yang hancur, apakah kita (akan dibangkitkan juga)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/079011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:12', 79, 12, 30, 583, 5724, 'قَالُوْا تِلْكَ اِذًا كَرَّةٌ خَاسِرَةٌ  ۘ', 'Mereka berkata, “Kalau demikian, itu suatu pengembalian yang merugikan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/079012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:13', 79, 13, 30, 583, 5725, 'فَاِنَّمَا هِيَ زَجْرَةٌ وَّاحِدَةٌۙ', '(Jangan dianggap sulit,) pengembalian itu (dilakukan) hanyalah dengan sekali tiupan.', '', 'https://everyayah.com/data/Alafasy_128kbps/079013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:14', 79, 14, 30, 583, 5726, 'فَاِذَا هُمْ بِالسَّاهِرَةِۗ', 'Seketika itu, mereka hidup kembali di bumi (yang baru).', '', 'https://everyayah.com/data/Alafasy_128kbps/079014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:15', 79, 15, 30, 583, 5727, 'هَلْ اَتٰىكَ حَدِيْثُ مُوْسٰىۘ', 'Sudah sampaikah kepadamu (Nabi Muhammad) kisah Musa?', '', 'https://everyayah.com/data/Alafasy_128kbps/079015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:16', 79, 16, 30, 584, 5728, 'اِذْ نَادٰىهُ رَبُّهٗ بِالْوَادِ الْمُقَدَّسِ طُوًىۚ', '(Ingatlah) ketika Tuhannya menyeru dia (Musa) di lembah suci, yaitu Lembah Tuwa,', '', 'https://everyayah.com/data/Alafasy_128kbps/079016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:17', 79, 17, 30, 584, 5729, 'اِذْهَبْ اِلٰى فِرْعَوْنَ اِنَّهٗ طَغٰىۖ', '“Pergilah engkau kepada Fir‘aun! Sesungguhnya dia telah melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/079017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:18', 79, 18, 30, 584, 5730, 'فَقُلْ هَلْ لَّكَ اِلٰٓى اَنْ تَزَكّٰىۙ', 'Lalu, katakanlah (kepada Fir‘aun), ‘Adakah keinginanmu untuk menyucikan diri (dari kesesatan)', '', 'https://everyayah.com/data/Alafasy_128kbps/079018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:19', 79, 19, 30, 584, 5731, 'وَاَهْدِيَكَ اِلٰى رَبِّكَ فَتَخْشٰىۚ', 'dan aku akan menunjukimu ke (jalan) Tuhanmu agar engkau takut (kepada-Nya)?’”', '', 'https://everyayah.com/data/Alafasy_128kbps/079019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:20', 79, 20, 30, 584, 5732, 'فَاَرٰىهُ الْاٰيَةَ الْكُبْرٰىۖ', 'Lalu, dia (Musa) memperlihatkan mukjizat yang besar kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/079020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:21', 79, 21, 30, 584, 5733, 'فَكَذَّبَ وَعَصٰىۖ', 'Akan tetapi, dia (Fir‘aun) mendustakan (kerasulan) dan mendurhakai (Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/079021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:22', 79, 22, 30, 584, 5734, 'ثُمَّ اَدْبَرَ يَسْعٰىۖ', 'Kemudian, dia berpaling seraya berusaha (menantang Musa).', '', 'https://everyayah.com/data/Alafasy_128kbps/079022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:23', 79, 23, 30, 584, 5735, 'فَحَشَرَ فَنَادٰىۖ', 'Maka, dia mengumpulkan (pembesar-pembesarnya), lalu berseru (memanggil kaumnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/079023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:24', 79, 24, 30, 584, 5736, 'فَقَالَ اَنَا۠ رَبُّكُمُ الْاَعْلٰىۖ', 'Dia berkata, “Akulah Tuhanmu yang paling tinggi.”', '', 'https://everyayah.com/data/Alafasy_128kbps/079024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:25', 79, 25, 30, 584, 5737, 'فَاَخَذَهُ اللّٰهُ نَكَالَ الْاٰخِرَةِ وَالْاُوْلٰىۗ', 'Maka, Allah menghukumnya dengan azab di akhirat dan (siksaan) di dunia.', '', 'https://everyayah.com/data/Alafasy_128kbps/079025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:26', 79, 26, 30, 584, 5738, 'اِنَّ فِيْ ذٰلِكَ لَعِبْرَةً لِّمَنْ يَّخْشٰى ۗ ࣖ', 'Sesungguhnya pada yang demikian itu benar-benar terdapat pelajaran bagi orang yang takut (kepada Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/079026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:27', 79, 27, 30, 584, 5739, 'ءَاَنْتُمْ اَشَدُّ خَلْقًا اَمِ السَّمَاۤءُ ۚ بَنٰىهَاۗ', 'Apakah penciptaan kamu yang lebih hebat ataukah langit yang telah dibangun-Nya?', '', 'https://everyayah.com/data/Alafasy_128kbps/079027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:28', 79, 28, 30, 584, 5740, 'رَفَعَ سَمْكَهَا فَسَوّٰىهَاۙ', 'Dia telah meninggikan bangunannya, lalu menyempurnakannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/079028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:29', 79, 29, 30, 584, 5741, 'وَاَغْطَشَ لَيْلَهَا وَاَخْرَجَ ضُحٰىهَاۖ', 'Dia menjadikan malamnya (gelap gulita) dan menjadikan siangnya (terang benderang).', '', 'https://everyayah.com/data/Alafasy_128kbps/079029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:30', 79, 30, 30, 584, 5742, 'وَالْاَرْضَ بَعْدَ ذٰلِكَ دَحٰىهَاۗ', 'Setelah itu, bumi Dia hamparkan (untuk dihuni).', '', 'https://everyayah.com/data/Alafasy_128kbps/079030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:31', 79, 31, 30, 584, 5743, 'اَخْرَجَ مِنْهَا مَاۤءَهَا وَمَرْعٰىهَاۖ', 'Darinya (bumi) Dia mengeluarkan air dan (menyediakan) tempat penggembalaan.', '', 'https://everyayah.com/data/Alafasy_128kbps/079031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:32', 79, 32, 30, 584, 5744, 'وَالْجِبَالَ اَرْسٰىهَاۙ', 'Gunung-gunung Dia pancangkan dengan kukuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/079032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:33', 79, 33, 30, 584, 5745, 'مَتَاعًا لَّكُمْ وَلِاَنْعَامِكُمْۗ', '(Semua itu disediakan) untuk kesenanganmu dan hewan ternakmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/079033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:34', 79, 34, 30, 584, 5746, 'فَاِذَا جَاۤءَتِ الطَّاۤمَّةُ الْكُبْرٰىۖ', 'Maka, apabila malapetaka terbesar (hari Kiamat) telah datang,', '', 'https://everyayah.com/data/Alafasy_128kbps/079034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:35', 79, 35, 30, 584, 5747, 'يَوْمَ يَتَذَكَّرُ الْاِنْسَانُ مَا سَعٰىۙ', 'pada hari (itu) manusia teringat apa yang telah dikerjakannya', '', 'https://everyayah.com/data/Alafasy_128kbps/079035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:36', 79, 36, 30, 584, 5748, 'وَبُرِّزَتِ الْجَحِيْمُ لِمَنْ يَّرٰى', 'dan (neraka) Jahim diperlihatkan dengan jelas kepada orang yang melihat(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/079036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:37', 79, 37, 30, 584, 5749, 'فَاَمَّا مَنْ طَغٰىۖ', 'Adapun orang yang melampaui batas', '', 'https://everyayah.com/data/Alafasy_128kbps/079037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:38', 79, 38, 30, 584, 5750, 'وَاٰثَرَ الْحَيٰوةَ الدُّنْيَاۙ', 'dan lebih mengutamakan kehidupan dunia,', '', 'https://everyayah.com/data/Alafasy_128kbps/079038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:39', 79, 39, 30, 584, 5751, 'فَاِنَّ الْجَحِيْمَ هِيَ الْمَأْوٰىۗ', 'sesungguhnya (neraka) Jahimlah tempat tinggal(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/079039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:40', 79, 40, 30, 584, 5752, 'وَاَمَّا مَنْ خَافَ مَقَامَ رَبِّهٖ وَنَهَى النَّفْسَ عَنِ الْهَوٰىۙ', 'Adapun orang-orang yang takut pada kebesaran Tuhannya dan menahan diri dari (keinginan) hawa nafsunya,', '', 'https://everyayah.com/data/Alafasy_128kbps/079040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:41', 79, 41, 30, 584, 5753, 'فَاِنَّ الْجَنَّةَ هِيَ الْمَأْوٰىۗ', 'sesungguhnya surgalah tempat tinggal(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/079041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:42', 79, 42, 30, 584, 5754, 'يَسْـَٔلُوْنَكَ عَنِ السَّاعَةِ اَيَّانَ مُرْسٰىهَاۗ', 'Mereka (orang-orang kafir) bertanya kepadamu (Nabi Muhammad) tentang hari Kiamat, “Kapankah terjadinya?” ', '', 'https://everyayah.com/data/Alafasy_128kbps/079042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:43', 79, 43, 30, 584, 5755, 'فِيْمَ اَنْتَ مِنْ ذِكْرٰىهَاۗ', 'Untuk apa engkau perlu menyebutkan (waktu)-nya?', '', 'https://everyayah.com/data/Alafasy_128kbps/079043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:44', 79, 44, 30, 584, 5756, 'اِلٰى رَبِّكَ مُنْتَهٰىهَاۗ', 'Kepada Tuhanmulah (dikembalikan) kesudahan (ketentuan waktu)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/079044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:45', 79, 45, 30, 584, 5757, 'اِنَّمَآ اَنْتَ مُنْذِرُ مَنْ يَّخْشٰىهَاۗ', 'Engkau (Nabi Muhammad) hanyalah pemberi peringatan kepada siapa yang takut padanya (hari Kiamat).', '', 'https://everyayah.com/data/Alafasy_128kbps/079045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('79:46', 79, 46, 30, 584, 5758, 'كَاَنَّهُمْ يَوْمَ يَرَوْنَهَا لَمْ يَلْبَثُوْٓا اِلَّا عَشِيَّةً اَوْ ضُحٰىهَا ࣖ', 'Pada hari ketika melihatnya (hari Kiamat itu), mereka merasa seakan-akan hanya (sebentar) tinggal (di dunia) pada waktu petang atau pagi.', '', 'https://everyayah.com/data/Alafasy_128kbps/079046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:1', 80, 1, 30, 585, 5759, 'عَبَسَ وَتَوَلّٰىٓۙ', 'Dia (Nabi Muhammad) berwajah masam dan berpaling', '', 'https://everyayah.com/data/Alafasy_128kbps/080001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:2', 80, 2, 30, 585, 5760, 'اَنْ جَاۤءَهُ الْاَعْمٰىۗ', 'karena seorang tunanetra (Abdullah bin Ummi Maktum) telah datang kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:3', 80, 3, 30, 585, 5761, 'وَمَا يُدْرِيْكَ لَعَلَّهٗ يَزَّكّٰىٓۙ', 'Tahukah engkau (Nabi Muhammad) boleh jadi dia ingin menyucikan dirinya (dari dosa)', '', 'https://everyayah.com/data/Alafasy_128kbps/080003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:4', 80, 4, 30, 585, 5762, 'اَوْ يَذَّكَّرُ فَتَنْفَعَهُ الذِّكْرٰىۗ', 'atau dia (ingin) mendapatkan pengajaran sehingga pengajaran itu bermanfaat baginya?', '', 'https://everyayah.com/data/Alafasy_128kbps/080004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:5', 80, 5, 30, 585, 5763, 'اَمَّا مَنِ اسْتَغْنٰىۙ', 'Adapun orang yang merasa dirinya serba cukup (para pembesar Quraisy),', '', 'https://everyayah.com/data/Alafasy_128kbps/080005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:6', 80, 6, 30, 585, 5764, 'فَاَنْتَ لَهٗ تَصَدّٰىۗ', 'engkau (Nabi Muhammad) memberi perhatian kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:7', 80, 7, 30, 585, 5765, 'وَمَا عَلَيْكَ اَلَّا يَزَّكّٰىۗ', 'Padahal, tidak ada (cela) atasmu kalau dia tidak menyucikan diri (beriman).', '', 'https://everyayah.com/data/Alafasy_128kbps/080007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:8', 80, 8, 30, 585, 5766, 'وَاَمَّا مَنْ جَاۤءَكَ يَسْعٰىۙ', 'Adapun orang yang datang kepadamu dengan bersegera (untuk mendapatkan pengajaran),', '', 'https://everyayah.com/data/Alafasy_128kbps/080008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:9', 80, 9, 30, 585, 5767, 'وَهُوَ يَخْشٰىۙ', 'sedangkan dia takut (kepada Allah),', '', 'https://everyayah.com/data/Alafasy_128kbps/080009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:10', 80, 10, 30, 585, 5768, 'فَاَنْتَ عَنْهُ تَلَهّٰىۚ', 'malah engkau (Nabi Muhammad) abaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/080010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:11', 80, 11, 30, 585, 5769, 'كَلَّآ اِنَّهَا تَذْكِرَةٌ ۚ', 'Sekali-kali jangan (begitu)! Sesungguhnya (ajaran Allah) itu merupakan peringatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/080011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:12', 80, 12, 30, 585, 5770, 'فَمَنْ شَاۤءَ ذَكَرَهٗ ۘ', 'Siapa yang menghendaki tentulah akan memperhatikannya', '', 'https://everyayah.com/data/Alafasy_128kbps/080012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:13', 80, 13, 30, 585, 5771, 'فِيْ صُحُفٍ مُّكَرَّمَةٍۙ', 'di dalam suhuf yang dimuliakan (di sisi Allah),', '', 'https://everyayah.com/data/Alafasy_128kbps/080013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:14', 80, 14, 30, 585, 5772, 'مَّرْفُوْعَةٍ مُّطَهَّرَةٍ ۢ ۙ', 'yang ditinggikan (kedudukannya) lagi disucikan', '', 'https://everyayah.com/data/Alafasy_128kbps/080014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:15', 80, 15, 30, 585, 5773, 'بِاَيْدِيْ سَفَرَةٍۙ', 'di tangan para utusan (malaikat)', '', 'https://everyayah.com/data/Alafasy_128kbps/080015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:16', 80, 16, 30, 585, 5774, 'كِرَامٍۢ بَرَرَةٍۗ', 'yang mulia lagi berbudi.', '', 'https://everyayah.com/data/Alafasy_128kbps/080016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:17', 80, 17, 30, 585, 5775, 'قُتِلَ الْاِنْسَانُ مَآ اَكْفَرَهٗۗ', 'Celakalah manusia! Alangkah kufur dia!', '', 'https://everyayah.com/data/Alafasy_128kbps/080017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:18', 80, 18, 30, 585, 5776, 'مِنْ اَيِّ شَيْءٍ خَلَقَهٗۗ', 'Dari apakah Dia menciptakannya?', '', 'https://everyayah.com/data/Alafasy_128kbps/080018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:19', 80, 19, 30, 585, 5777, 'مِنْ نُّطْفَةٍۗ خَلَقَهٗ فَقَدَّرَهٗۗ', 'Dia menciptakannya dari setetes mani, lalu menentukan (takdir)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:20', 80, 20, 30, 585, 5778, 'ثُمَّ السَّبِيْلَ يَسَّرَهٗۙ', 'Kemudian, jalannya Dia mudahkan.746)', '746) Maksudnya adalah memudahkan kelahirannya atau mempermudah baginya untuk menempuh jalan yang benar atau jalan yang sesat.', 'https://everyayah.com/data/Alafasy_128kbps/080020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:21', 80, 21, 30, 585, 5779, 'ثُمَّ اَمَاتَهٗ فَاَقْبَرَهٗۙ', 'Kemudian, Dia mematikannya lalu menguburkannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:22', 80, 22, 30, 585, 5780, 'ثُمَّ اِذَا شَاۤءَ اَنْشَرَهٗۗ', 'Kemudian, jika menghendaki, Dia membangkitkannya kembali.', '', 'https://everyayah.com/data/Alafasy_128kbps/080022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:23', 80, 23, 30, 585, 5781, 'كَلَّا لَمَّا يَقْضِ مَآ اَمَرَهٗۗ', 'Sekali-kali jangan (begitu)! Dia (manusia) itu belum melaksanakan apa yang Dia (Allah) perintahkan kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:24', 80, 24, 30, 585, 5782, 'فَلْيَنْظُرِ الْاِنْسَانُ اِلٰى طَعَامِهٖٓ ۙ ', ' Maka, hendaklah manusia itu memperhatikan makanannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:25', 80, 25, 30, 585, 5783, 'اَنَّا صَبَبْنَا الْمَاۤءَ صَبًّاۙ', 'Sesungguhnya Kami telah mencurahkan air (dari langit) dengan berlimpah. ', '', 'https://everyayah.com/data/Alafasy_128kbps/080025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:26', 80, 26, 30, 585, 5784, 'ثُمَّ شَقَقْنَا الْاَرْضَ شَقًّاۙ', 'Kemudian, Kami belah bumi dengan sebaik-baiknya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:27', 80, 27, 30, 585, 5785, 'فَاَنْۢبَتْنَا فِيْهَا حَبًّاۙ', 'Lalu, Kami tumbuhkan padanya biji-bijian,', '', 'https://everyayah.com/data/Alafasy_128kbps/080027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:28', 80, 28, 30, 585, 5786, 'وَّعِنَبًا وَّقَضْبًاۙ', 'anggur, sayur-sayuran,', '', 'https://everyayah.com/data/Alafasy_128kbps/080028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:29', 80, 29, 30, 585, 5787, 'وَّزَيْتُوْنًا وَّنَخْلًاۙ', 'zaitun, pohon kurma,', '', 'https://everyayah.com/data/Alafasy_128kbps/080029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:30', 80, 30, 30, 585, 5788, 'وَّحَدَاۤىِٕقَ غُلْبًا', 'kebun-kebun (yang) rindang,', '', 'https://everyayah.com/data/Alafasy_128kbps/080030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:31', 80, 31, 30, 585, 5789, 'وَفَاكِهَةً وَّاَبًّا', 'buah-buahan, dan rerumputan.', '', 'https://everyayah.com/data/Alafasy_128kbps/080031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:32', 80, 32, 30, 585, 5790, 'مَتَاعًا لَّكُمْ وَلِاَنْعَامِكُمْۗ', '(Semua itu disediakan) untuk kesenanganmu dan hewan-hewan ternakmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/080032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:33', 80, 33, 30, 585, 5791, 'فَاِذَا جَاۤءَتِ الصَّاۤخَّةُ ۖ', 'Maka, apabila datang suara yang memekakkan (dari tiupan sangkakala),', '', 'https://everyayah.com/data/Alafasy_128kbps/080033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:34', 80, 34, 30, 585, 5792, 'يَوْمَ يَفِرُّ الْمَرْءُ مِنْ اَخِيْهِۙ', 'pada hari itu manusia lari dari saudaranya,', '', 'https://everyayah.com/data/Alafasy_128kbps/080034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:35', 80, 35, 30, 585, 5793, 'وَاُمِّهٖ وَاَبِيْهِۙ', '(dari) ibu dan bapaknya,', '', 'https://everyayah.com/data/Alafasy_128kbps/080035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:36', 80, 36, 30, 585, 5794, 'وَصَاحِبَتِهٖ وَبَنِيْهِۗ', 'serta (dari) istri dan anak-anaknya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:37', 80, 37, 30, 585, 5795, 'لِكُلِّ امْرِئٍ مِّنْهُمْ يَوْمَىِٕذٍ شَأْنٌ يُّغْنِيْهِۗ', 'Setiap orang dari mereka pada hari itu mempunyai urusan yang menyibukkannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/080037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:38', 80, 38, 30, 585, 5796, 'وُجُوْهٌ يَّوْمَىِٕذٍ مُّسْفِرَةٌۙ', 'Pada hari itu ada wajah-wajah yang berseri-seri,', '', 'https://everyayah.com/data/Alafasy_128kbps/080038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:39', 80, 39, 30, 585, 5797, 'ضَاحِكَةٌ مُّسْتَبْشِرَةٌ ۚ', 'tertawa lagi gembira ria.', '', 'https://everyayah.com/data/Alafasy_128kbps/080039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:40', 80, 40, 30, 585, 5798, 'وَوُجُوْهٌ يَّوْمَىِٕذٍ عَلَيْهَا غَبَرَةٌۙ', 'Pada hari itu ada (pula) wajah-wajah yang tertutup debu (suram)', '', 'https://everyayah.com/data/Alafasy_128kbps/080040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:41', 80, 41, 30, 585, 5799, 'تَرْهَقُهَا قَتَرَةٌ ۗ', 'dan tertutup oleh kegelapan (ditimpa kehinaan dan kesusahan).', '', 'https://everyayah.com/data/Alafasy_128kbps/080041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('80:42', 80, 42, 30, 585, 5800, 'اُولٰۤىِٕكَ هُمُ الْكَفَرَةُ الْفَجَرَةُ ࣖ', 'Mereka itulah orang-orang kafir lagi para pendurhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/080042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:1', 81, 1, 30, 586, 5801, 'اِذَا الشَّمْسُ كُوِّرَتْۖ', 'Apabila matahari digulung,', '', 'https://everyayah.com/data/Alafasy_128kbps/081001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:2', 81, 2, 30, 586, 5802, 'وَاِذَا النُّجُوْمُ انْكَدَرَتْۖ', 'apabila bintang-bintang berjatuhan,', '', 'https://everyayah.com/data/Alafasy_128kbps/081002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:3', 81, 3, 30, 586, 5803, 'وَاِذَا الْجِبَالُ سُيِّرَتْۖ', 'apabila gunung-gunung dihancurkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/081003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:4', 81, 4, 30, 586, 5804, 'وَاِذَا الْعِشَارُ عُطِّلَتْۖ', 'apabila unta-unta yang bunting ditinggalkan (tidak terurus),', '', 'https://everyayah.com/data/Alafasy_128kbps/081004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:5', 81, 5, 30, 586, 5805, 'وَاِذَا الْوُحُوْشُ حُشِرَتْۖ', 'apabila binatang-binatang liar dikumpulkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/081005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:6', 81, 6, 30, 586, 5806, 'وَاِذَا الْبِحَارُ سُجِّرَتْۖ', 'apabila lautan dipanaskan,', '', 'https://everyayah.com/data/Alafasy_128kbps/081006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:7', 81, 7, 30, 586, 5807, 'وَاِذَا النُّفُوْسُ زُوِّجَتْۖ', 'apabila roh-roh dipertemukan (dengan tubuh), ', '', 'https://everyayah.com/data/Alafasy_128kbps/081007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:8', 81, 8, 30, 586, 5808, 'وَاِذَا الْمَوْءٗدَةُ سُىِٕلَتْۖ ', 'apabila bayi-bayi perempuan yang dikubur hidup-hidup ditanya, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:9', 81, 9, 30, 586, 5809, 'بِاَيِّ ذَنْۢبٍ قُتِلَتْۚ', '“Karena dosa apa dia dibunuh,”', '', 'https://everyayah.com/data/Alafasy_128kbps/081009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:10', 81, 10, 30, 586, 5810, 'وَاِذَا الصُّحُفُ نُشِرَتْۖ', 'apabila lembaran-lembaran (catatan amal) telah dibuka lebar-lebar, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:11', 81, 11, 30, 586, 5811, 'وَاِذَا السَّمَاۤءُ كُشِطَتْۖ', 'apabila langit dilenyapkan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:12', 81, 12, 30, 586, 5812, 'وَاِذَا الْجَحِيْمُ سُعِّرَتْۖ', 'apabila (neraka) Jahim dinyalakan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:13', 81, 13, 30, 586, 5813, 'وَاِذَا الْجَنَّةُ اُزْلِفَتْۖ', 'dan apabila surga didekatkan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:14', 81, 14, 30, 586, 5814, 'عَلِمَتْ نَفْسٌ مَّآ اَحْضَرَتْۗ', 'setiap jiwa akan mengetahui apa yang telah dikerjakannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/081014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:15', 81, 15, 30, 586, 5815, 'فَلَآ اُقْسِمُ بِالْخُنَّسِۙ', 'Aku bersumpah demi bintang-bintang', '', 'https://everyayah.com/data/Alafasy_128kbps/081015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:16', 81, 16, 30, 586, 5816, 'الْجَوَارِ الْكُنَّسِۙ', 'yang beredar lagi terbenam, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:17', 81, 17, 30, 586, 5817, 'وَالَّيْلِ اِذَا عَسْعَسَۙ', 'demi malam apabila telah larut,', '', 'https://everyayah.com/data/Alafasy_128kbps/081017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:18', 81, 18, 30, 586, 5818, 'وَالصُّبْحِ اِذَا تَنَفَّسَۙ', 'demi subuh apabila (fajar) telah menyingsing, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:19', 81, 19, 30, 586, 5819, 'اِنَّهٗ لَقَوْلُ رَسُوْلٍ كَرِيْمٍۙ', 'sesungguhnya (Al-Qur’an) itu benar-benar firman (Allah yang dibawa oleh) utusan yang mulia (Jibril)', '', 'https://everyayah.com/data/Alafasy_128kbps/081019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:20', 81, 20, 30, 586, 5820, 'ذِيْ قُوَّةٍ عِنْدَ ذِى الْعَرْشِ مَكِيْنٍۙ', 'yang memiliki kekuatan dan kedudukan tinggi di sisi (Allah) yang memiliki ʻArasy,', '', 'https://everyayah.com/data/Alafasy_128kbps/081020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:21', 81, 21, 30, 586, 5821, 'مُّطَاعٍ ثَمَّ اَمِيْنٍۗ', 'yang di sana (Jibril) ditaati lagi dipercaya.', '', 'https://everyayah.com/data/Alafasy_128kbps/081021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:22', 81, 22, 30, 586, 5822, 'وَمَا صَاحِبُكُمْ بِمَجْنُوْنٍۚ', 'Temanmu (Nabi Muhammad) itu bukanlah orang gila. ', '', 'https://everyayah.com/data/Alafasy_128kbps/081022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:23', 81, 23, 30, 586, 5823, 'وَلَقَدْ رَاٰهُ بِالْاُفُقِ الْمُبِيْنِۚ', 'Sungguh, dia (Nabi Muhammad) benar-benar telah melihatnya (Jibril) di ufuk yang terang. ', '', 'https://everyayah.com/data/Alafasy_128kbps/081023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:24', 81, 24, 30, 586, 5824, 'وَمَا هُوَ عَلَى الْغَيْبِ بِضَنِيْنٍۚ', 'Dia (Nabi Muhammad) bukanlah seorang yang kikir (enggan) untuk menerangkan yang gaib.', '', 'https://everyayah.com/data/Alafasy_128kbps/081024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:25', 81, 25, 30, 586, 5825, 'وَمَا هُوَ بِقَوْلِ شَيْطٰنٍ رَّجِيْمٍۚ', '(Al-Qur’an) itu bukanlah perkataan setan yang terkutuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/081025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:26', 81, 26, 30, 586, 5826, 'فَاَيْنَ تَذْهَبُوْنَۗ', 'Maka, ke manakah kamu akan pergi?747)', '747) Setelah diterangkan bahwa Al-Qur’an itu benar-benar datang dari Allah dan di dalamnya ada pelajaran dan petunjuk yang memimpin manusia ke jalan yang lurus, ditanyakanlah kepada orang-orang kafir itu, “Jalan manakah yang akan kamu tempuh?”', 'https://everyayah.com/data/Alafasy_128kbps/081026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:27', 81, 27, 30, 586, 5827, 'اِنْ هُوَ اِلَّا ذِكْرٌ لِّلْعٰلَمِيْنَۙ', '(Al-Qur’an) itu tidak lain, kecuali peringatan bagi semesta alam, ', '', 'https://everyayah.com/data/Alafasy_128kbps/081027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:28', 81, 28, 30, 586, 5828, 'لِمَنْ شَاۤءَ مِنْكُمْ اَنْ يَّسْتَقِيْمَۗ', '(yaitu) bagi siapa di antaramu yang hendak menempuh jalan yang lurus. ', '', 'https://everyayah.com/data/Alafasy_128kbps/081028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('81:29', 81, 29, 30, 586, 5829, 'وَمَا تَشَاۤءُوْنَ اِلَّآ اَنْ يَّشَاۤءَ اللّٰهُ رَبُّ الْعٰلَمِيْنَ ࣖ', 'Kamu tidak dapat berkehendak, kecuali apabila dikehendaki Allah, Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/081029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:1', 82, 1, 30, 587, 5830, 'اِذَا السَّمَاۤءُ انْفَطَرَتْۙ', 'Apabila langit terbelah,', '', 'https://everyayah.com/data/Alafasy_128kbps/082001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:2', 82, 2, 30, 587, 5831, 'وَاِذَا الْكَوَاكِبُ انْتَثَرَتْۙ', 'apabila bintang-bintang jatuh berserakan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/082002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:3', 82, 3, 30, 587, 5832, 'وَاِذَا الْبِحَارُ فُجِّرَتْۙ', 'apabila lautan diluapkan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/082003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:4', 82, 4, 30, 587, 5833, 'وَاِذَا الْقُبُوْرُ بُعْثِرَتْۙ', 'dan apabila kuburan-kuburan dibongkar,', '', 'https://everyayah.com/data/Alafasy_128kbps/082004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:5', 82, 5, 30, 587, 5834, 'عَلِمَتْ نَفْسٌ مَّا قَدَّمَتْ وَاَخَّرَتْۗ', 'setiap jiwa akan mengetahui apa yang telah dikerjakan dan yang dilalaikan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/082005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:6', 82, 6, 30, 587, 5835, 'يٰٓاَيُّهَا الْاِنْسَانُ مَا غَرَّكَ بِرَبِّكَ الْكَرِيْمِۙ', 'Wahai manusia, apakah yang telah memperdayakanmu (berbuat durhaka) terhadap Tuhanmu Yang Maha Mulia,', '', 'https://everyayah.com/data/Alafasy_128kbps/082006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:7', 82, 7, 30, 587, 5836, 'الَّذِيْ خَلَقَكَ فَسَوّٰىكَ فَعَدَلَكَۙ', 'yang telah menciptakanmu lalu menyempurnakan kejadianmu dan menjadikan (susunan tubuh)-mu seimbang?', '', 'https://everyayah.com/data/Alafasy_128kbps/082007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:8', 82, 8, 30, 587, 5837, 'فِيْٓ اَيِّ صُوْرَةٍ مَّا شَاۤءَ رَكَّبَكَۗ', 'Dalam bentuk apa saja yang dikehendaki, Dia menyusun (tubuh)-mu.', '', 'https://everyayah.com/data/Alafasy_128kbps/082008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:9', 82, 9, 30, 587, 5838, 'كَلَّا بَلْ تُكَذِّبُوْنَ بِالدِّيْنِۙ', 'Jangan sekali-kali begitu! Bahkan, kamu mendustakan hari Pembalasan.', '', 'https://everyayah.com/data/Alafasy_128kbps/082009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:10', 82, 10, 30, 587, 5839, 'وَاِنَّ عَلَيْكُمْ لَحٰفِظِيْنَۙ', 'Sesungguhnya bagi kamu ada (malaikat-malaikat) pengawas', '', 'https://everyayah.com/data/Alafasy_128kbps/082010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:11', 82, 11, 30, 587, 5840, 'كِرَامًا كٰتِبِيْنَۙ', 'yang mulia (di sisi Allah) dan mencatat (amal perbuatanmu).', '', 'https://everyayah.com/data/Alafasy_128kbps/082011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:12', 82, 12, 30, 587, 5841, 'يَعْلَمُوْنَ مَا تَفْعَلُوْنَ', 'Mereka mengetahui apa yang kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/082012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:13', 82, 13, 30, 587, 5842, 'اِنَّ الْاَبْرَارَ لَفِيْ نَعِيْمٍۙ', 'Sesungguhnya orang-orang yang berbakti benar-benar berada dalam (surga yang penuh) kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/082013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:14', 82, 14, 30, 587, 5843, 'وَّاِنَّ الْفُجَّارَ لَفِيْ جَحِيْمٍ', 'Sesungguhnya orang-orang yang durhaka benar-benar berada dalam (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/082014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:15', 82, 15, 30, 587, 5844, 'يَصْلَوْنَهَا يَوْمَ الدِّيْنِ', 'Mereka memasukinya pada hari Pembalasan.', '', 'https://everyayah.com/data/Alafasy_128kbps/082015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:16', 82, 16, 30, 587, 5845, 'وَمَا هُمْ عَنْهَا بِغَاۤىِٕبِيْنَۗ', 'Mereka tidak mungkin keluar dari (neraka) itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/082016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:17', 82, 17, 30, 587, 5846, 'وَمَآ اَدْرٰىكَ مَا يَوْمُ الدِّيْنِۙ', 'Tahukah engkau apakah hari Pembalasan itu? ', '', 'https://everyayah.com/data/Alafasy_128kbps/082017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:18', 82, 18, 30, 587, 5847, 'ثُمَّ مَآ اَدْرٰىكَ مَا يَوْمُ الدِّيْنِۗ', 'Kemudian, tahukah engkau apakah hari Pembalasan itu? ', '', 'https://everyayah.com/data/Alafasy_128kbps/082018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('82:19', 82, 19, 30, 587, 5848, 'يَوْمَ لَا تَمْلِكُ نَفْسٌ لِّنَفْسٍ شَيْـًٔا ۗوَالْاَمْرُ يَوْمَىِٕذٍ لِّلّٰهِ ࣖ', '(Itulah) hari (ketika) seseorang tidak berdaya (menolong) orang lain sedikit pun. Segala urusan pada hari itu adalah milik Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/082019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:1', 83, 1, 30, 587, 5849, 'وَيْلٌ لِّلْمُطَفِّفِيْنَۙ', 'Celakalah orang-orang yang curang (dalam menakar dan menimbang)!', '', 'https://everyayah.com/data/Alafasy_128kbps/083001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:2', 83, 2, 30, 587, 5850, 'الَّذِيْنَ اِذَا اكْتَالُوْا عَلَى النَّاسِ يَسْتَوْفُوْنَۖ', '(Mereka adalah) orang-orang yang apabila menerima takaran dari orang lain, mereka minta dipenuhi.', '', 'https://everyayah.com/data/Alafasy_128kbps/083002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:3', 83, 3, 30, 587, 5851, 'وَاِذَا كَالُوْهُمْ اَوْ وَّزَنُوْهُمْ يُخْسِرُوْنَۗ', '(Sebaliknya,) apabila mereka menakar atau menimbang untuk orang lain, mereka kurangi. ', '', 'https://everyayah.com/data/Alafasy_128kbps/083003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:4', 83, 4, 30, 587, 5852, 'اَلَا يَظُنُّ اُولٰۤىِٕكَ اَنَّهُمْ مَّبْعُوْثُوْنَۙ', 'Tidakkah mereka mengira (bahwa) sesungguhnya mereka akan dibangkitkan', '', 'https://everyayah.com/data/Alafasy_128kbps/083004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:5', 83, 5, 30, 587, 5853, 'لِيَوْمٍ عَظِيْمٍۙ', 'pada suatu hari yang besar (Kiamat),', '', 'https://everyayah.com/data/Alafasy_128kbps/083005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:6', 83, 6, 30, 587, 5854, 'يَّوْمَ يَقُوْمُ النَّاسُ لِرَبِّ الْعٰلَمِيْنَۗ', '(yaitu) hari (ketika) manusia bangkit menghadap Tuhan seluruh alam?', '', 'https://everyayah.com/data/Alafasy_128kbps/083006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:7', 83, 7, 30, 588, 5855, 'كَلَّآ اِنَّ كِتٰبَ الْفُجَّارِ لَفِيْ سِجِّيْنٍۗ', 'Jangan sekali-kali begitu! Sesungguhnya catatan orang yang durhaka benar-benar (tersimpan) dalam Sijjīn.748)', '748) Sijjīn adalah nama kitab yang mencatat segala perbuatan orang-orang yang durhaka.', 'https://everyayah.com/data/Alafasy_128kbps/083007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:8', 83, 8, 30, 588, 5856, 'وَمَآ اَدْرٰىكَ مَا سِجِّيْنٌۗ', 'Tahukah engkau apakah Sijjīn itu? ', '', 'https://everyayah.com/data/Alafasy_128kbps/083008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:9', 83, 9, 30, 588, 5857, 'كِتٰبٌ مَّرْقُوْمٌۗ', '(Ia adalah) kitab yang berisi catatan (amal).', '', 'https://everyayah.com/data/Alafasy_128kbps/083009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:10', 83, 10, 30, 588, 5858, 'وَيْلٌ يَّوْمَىِٕذٍ لِّلْمُكَذِّبِيْنَۙ', 'Celakalah pada hari itu bagi para pendusta,', '', 'https://everyayah.com/data/Alafasy_128kbps/083010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:11', 83, 11, 30, 588, 5859, 'الَّذِيْنَ يُكَذِّبُوْنَ بِيَوْمِ الدِّيْنِۗ', 'yaitu orang-orang yang mendustakan hari Pembalasan.', '', 'https://everyayah.com/data/Alafasy_128kbps/083011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:12', 83, 12, 30, 588, 5860, 'وَمَا يُكَذِّبُ بِهٖٓ اِلَّا كُلُّ مُعْتَدٍ اَثِيْمٍۙ', 'Tidak ada yang mendustakannya, kecuali setiap orang yang melampaui batas lagi sangat berdosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/083012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:13', 83, 13, 30, 588, 5861, 'اِذَا تُتْلٰى عَلَيْهِ اٰيٰتُنَا قَالَ اَسَاطِيْرُ الْاَوَّلِيْنَۗ', 'Apabila dibacakan kepadanya ayat-ayat Kami, dia berkata, “(Itu adalah) dongeng orang-orang dahulu.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/083013.mp3');
PRAGMA foreign_keys = ON;
